from yaml import Loader


def yaml_to_json(yaml_file_path: str) -> str:
    try:
        with open(yaml_file_path, 'r') as file:
            yaml_content = file.read()
    except FileNotFoundError:
        return 'Error: File not found.'
    except PermissionError:
        return 'Error: Permission denied.'
    except Exception as e:
        return f'Error: Unable to read file: {str(e)}'

    try:
        data = yaml.load(yaml_content, Loader=Loader)
    except yaml.YAMLError as e:
        return f'Error: Invalid YAML content: {str(e)}'
    except Exception as e:
        return f'Error: Unable to parse YAML: {str(e)}'

    try:
        json_str = json.dumps(data)
    except TypeError as e:
        return f'Error: Unable to convert to JSON: {str(e)}'
    except Exception as e:
        return f'Error: JSON conversion error: {str(e)}'

    return json_str

